252	function healthProblems(health: CurrentsHealth | null): string[] {
253	  if (!health) return ["Currents health endpoint is unreachable."];
254	  const problems = [...health.disabled_reasons];
255	  if (!health.last_cycle_at) problems.push("scheduler has not reported a cycle");
256	  if (health.events_last_24h === 0) problems.push("no X events recorded in the last 24h");
257	  if (health.opinions_last_24h === 0) problems.push("no Currents opinions generated in the last 24h");
258	  return problems;
259	}
