270	      )
271	      .catch((err) => {
272	        console.error("[dashboard] embedding health query failed:", err);
273	        return null;
274	      }),
275	  ]);
276	  const problems = healthProblems(health);
277	  const healthy = problems.length === 0;
278	  const accent = healthy ? "rgba(160, 211, 170, 0.9)" : "var(--ember)";
279	  const embeddingAccent = embeddingHealthColor(embeddingsHealthy);
