96	    setBusyId(null);
97	  }
98	
99	  async function handleUndo() {
100	    if (!lastHidden || sectionBusy) return;
101	    const hidden = lastHidden;
102	    if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
103	
104	    setError("");
105	    setSectionBusy(true);
106	    setLastHidden(null);
107	    setConclusions((items) => insertConclusionAt(items, hidden));
108	    setHiddenCount((count) => Math.max(0, count - 1));
109	
110	    const result = await undoConclusionDismissalFromMyDashboard(hidden.conclusion.id);
111	    if (!result.ok) {
112	      setConclusions((items) =>
113	        items.filter((item) => item.id !== hidden.conclusion.id),
114	      );
115	      setHiddenCount((count) => count + 1);
116	      setLastHidden(hidden);
117	      setError(result.error || "Undo failed.");
118	    } else {
119	      router.refresh();
120	    }
121	    setSectionBusy(false);
122	  }
123	
124	  async function handleShowAllAgain() {
125	    if (hiddenCount === 0 || sectionBusy) return;
126	    if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
127	
128	    const previousCount = hiddenCount;
129	    setError("");
130	    setSectionBusy(true);
131	    setLastHidden(null);
132	    setHiddenCount(0);
133	
134	    const result = await showAllDashboardConclusionsAgain();
135	    if (!result.ok) {
136	      setHiddenCount(previousCount);
137	      setError(result.error || "Could not show hidden conclusions.");
138	    } else {
139	      router.refresh();
140	    }
141	    setSectionBusy(false);
142	  }
143	
144	  return (
145	    <section
146	      className="ascii-frame"
147	      data-label={`CONCLUSIONS · ${toRoman(conclusions.length) || "0"}`}
148	    >
149	      <div
150	        className="mono"
151	        style={{
152	          display: "flex",
153	          justifyContent: "space-between",
154	          alignItems: "center",
155	          gap: "0.75rem",
156	          marginBottom: "0.65rem",
157	          fontSize: "0.58rem",
158	          letterSpacing: "0.16em",
159	          textTransform: "uppercase",
160	          color: "var(--parchment-dim)",
161	        }}
162	      >
163	        <span>{hiddenCount} hidden from your view ·</span>
164	        <button
165	          type="button"
166	          onClick={handleShowAllAgain}
167	          disabled={hiddenCount === 0 || sectionBusy}
168	          style={{
169	            display: "inline-flex",
170	            alignItems: "center",
171	            gap: "0.3rem",
172	            border: "none",
173	            background: "none",
174	            color: hiddenCount === 0 ? "var(--parchment-dim)" : "var(--amber)",
175	            cursor: hiddenCount === 0 ? "default" : "pointer",
176	            font: "inherit",
177	            letterSpacing: "inherit",
178	            textTransform: "inherit",
179	            padding: 0,
180	            opacity: hiddenCount === 0 ? 0.45 : 1,
181	          }}
182	        >
183	          <RotateCcw size={12} aria-hidden="true" />
184	          Show all again
