187	
188	      <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
189	        {conclusions.length === 0 ? (
190	          <LatinEmpty
191	            latin="Adhuc nihil firmandum."
192	            english={
193	              hiddenCount > 0
194	                ? "Some conclusions are hidden from your dashboard."
195	                : "Nothing yet for the firm to affirm."
196	            }
