468	            boxShadow: "0 12px 28px rgba(0,0,0,0.35)",
469	          }}
470	        >
471	          Dismiss is a private dashboard hide. Deletion opens peer review.
472	        </div>
473	      ) : null}
474	
475	      {open ? (
476	        <div
477	          id={menuId}
478	          role="menu"
479	          aria-label="Conclusion actions"
480	          onKeyDown={onMenuKeyDown}
481	          style={{
482	            position: "absolute",
