590	function toRoman(n: number): string {
591	  if (!n || n < 1) return "";
592	  const table: [number, string][] = [
593	    [10, "X"],
594	    [9, "IX"],
595	    [5, "V"],
596	    [4, "IV"],
597	    [1, "I"],
598	  ];
599	  let out = "";
600	  let rem = n;
601	  for (const [value, roman] of table) {
602	    while (rem >= value) {
603	      out += roman;
604	      rem -= value;
605	    }
606	  }
607	  return out;
608	}
