              textDecoration: "none",
            }}
          >
            ← Knowledge
          </Link>
          <form action={requestConclusionDeletion}>
            <input type="hidden" name="conclusionId" value={id} />
            <button
              type="submit"
              className="btn"
              style={{
                fontSize: "0.65rem",
                color: "var(--ember)",
                borderColor: "var(--ember)",
              }}
