            <CascadeTab conclusionId={id} />
          ) : activeTab === "peer" ? (
            <PeerReviewTab conclusionId={id} />
          ) : activeTab === "blindspots" ? (
            <BlindspotsPanel
              conclusionId={id}
              organizationId={tenant.organizationId}
            />
          ) : activeTab === "related" ? (
            <RelatedTab conclusionId={id} />
          ) : activeTab === "lineage" ? (
            <LineagePanel conclusionId={id} />
          ) : (
            <HistoryTab conclusionId={id} />
          )}
        </section>

        <nav
          style={{
            marginTop: "2rem",
            display: "flex",
            alignItems: "center",
            gap: "1rem",
            flexWrap: "wrap",
          }}
        >
          <Link
            href="/knowledge?tab=conclusions"
            style={{
              fontFamily: "'Cinzel', serif",
              fontSize: "0.7rem",
              letterSpacing: "0.1em",
              color: "var(--parchment-dim)",
              textDecoration: "none",
            }}
          >
            ← Knowledge
          </Link>
          <form action={requestConclusionDeletion}>
            <input type="hidden" name="conclusionId" value={id} />
            <button
              type="submit"
              className="btn"
              style={{
                fontSize: "0.65rem",
                color: "var(--ember)",
                borderColor: "var(--ember)",
              }}
            >
