      <summary
        style={{
          cursor: ids.length > 0 ? "pointer" : "default",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "baseline",
          listStyle: ids.length > 0 ? undefined : "none",
        }}
      >
        <span
          style={{
            fontFamily: "'Cinzel', serif",
            fontSize: "0.6rem",
            letterSpacing: "0.15em",
            textTransform: "uppercase",
            color: "var(--parchment-dim)",
          }}
        >
          {label}
        </span>
        <span
          style={{
            fontSize: "1.1rem",
            color: "var(--gold)",
            fontFamily: "'Cinzel', serif",
          }}
        >
          {ids.length}
        </span>
      </summary>
      {ids.length === 0 ? null : (
        <div style={{ marginTop: "0.5rem", display: "flex", flexDirection: "column", gap: "0.4rem" }}>
          {ids.map((id) => {
            const text = idTextMap[id];
            return (
              <div
                key={id}
                style={{
                  padding: "0.35rem 0.5rem",
                  borderLeft: "2px solid var(--border)",
                }}
              >
                {text ? (
                  <p style={{ margin: 0, fontSize: "0.85rem", color: "var(--parchment)" }}>
                    {text}
                  </p>
                ) : (
                  <p
                    style={{
                      margin: 0,
                      fontSize: "0.75rem",
                      color: "var(--parchment-dim)",
                      fontStyle: "italic",
                    }}
                  >
                    {id.slice(0, 12)}… — text unavailable (may require Noosphere
                    connection)
                  </p>
                )}
              </div>
            );
          })}
        </div>
      )}
    </details>
  );
}

