    (ids: string[]) => {
      writeState({ ...state, selection: ids, focused: null });
    },
    [state, writeState],
  );

  const onClearSelection = useCallback(() => {
    writeState({ ...state, selection: [], focused: null });
  }, [state, writeState]);

  const onPointClick = useCallback(
    (id: string) => {
