function isEditableTarget(target: EventTarget | null): boolean {
  if (!target) return false;
  // `Element` may not exist in non-DOM test environments. Probe for
  // it lazily and fall back to duck-typing on tagName.
  const ElementCtor =
    typeof globalThis !== "undefined"
      ? (globalThis as { Element?: unknown }).Element
      : undefined;
  if (typeof ElementCtor === "function" && !(target instanceof (ElementCtor as { prototype: object }).constructor)) {
    return false;
  }
